using Microsoft.EntityFrameworkCore; using ModularMonolith.Modules.Orders.Domain; namespace ModularMonolith.Modules.Orders.Infrastructure;
internal sealed class OrdersDbContext(DbContextOptions<OrdersDbContext> options):DbContext(options){ internal DbSet<Order> Orders=>Set<Order>(); protected override void OnModelCreating(ModelBuilder b){var o=b.Entity<Order>(); o.ToTable("Orders"); o.HasKey(x=>x.Id); o.Property(x=>x.Total).HasPrecision(18,2); o.HasMany(x=>x.Items).WithOne().HasForeignKey("OrderId").OnDelete(DeleteBehavior.Cascade); var i=b.Entity<OrderItem>(); i.ToTable("OrderItems"); i.HasKey(x=>x.Id); i.Property(x=>x.ProductName).HasMaxLength(200); i.Property(x=>x.UnitPrice).HasPrecision(18,2); i.Property(x=>x.LineTotal).HasPrecision(18,2);}}
